// Toggle Script Call — Toggles "Staggered" condition and "Haste" buff

// Toggle Staggered condition
if (typeof actor.toggleCondition === "function") {
  await actor.toggleCondition("staggered");
} else {
  const current = actor.system.conditions?.["staggered"] ?? false;
  await actor.update({ "system.conditions.staggered": !current });
}

// Toggle Haste buff
const hasteBuff = actor.items.find(i => i.type === "buff" && i.name === "Haste");

if (!hasteBuff) {
  ui.notifications.warn(`No buff named "Haste" found on ${actor.name}.`);
} else {
  await hasteBuff.update({ "system.active": !hasteBuff.system.active });
}
